import matplotlib; matplotlib.use("Agg"); import matplotlib.pyplot as plt; import matplotlib.patches as patches; import numpy as np; fig, ax = plt.subplots(figsize=(5, 4)); ax.set_aspect("equal"); ax.axis("off"); triangle_pts = np.array([[0, 0], [4, 0], [0, 3]]); poly = patches.Polygon(triangle_pts, closed=True, facecolor="#eaf2fb", edgecolor="#1a1a1a", linewidth=2); ax.add_patch(poly); rect = patches.Rectangle((0, 0), 0.3, 0.3, fill=False, edgecolor="#1a1a1a", linewidth=1.5); ax.add_patch(rect); ax.text(2, -0.2, "4", ha="center", va="top", fontsize=12); ax.text(-0.2, 1.5, "3", ha="right", va="center", fontsize=12); ax.text(2.2, 1.7, "5", ha="left", va="bottom", fontsize=12); ax.set_xlim(-1, 5); ax.set_ylim(-1, 4); plt.savefig("out.png", dpi=150)